#include <iostream>
#include <climits>
using namespace std;
class Solution {
public:
 int solve(int n, int k) { if (k > n - k) k = n - k; int ans = 1; for (int i = 1; i <= k; i++) { ans = ans * (n - i + 1) / i; } return ans; }
};
int main() { int n, k; cin >> n >> k; cout << Solution().solve(n, k) << endl; return 0; }
